// Validator for deserialized messages
object MessageValidator {

  private val MaxStringLength = 10000
  private val AllowedCommands = Set("ping", "status", "list", "info", "stop")
  private val MaxArgs = 10

  def validate(msg: SafeMessage): Either[String, SafeMessage] = msg match {
    case m: TextMessage =>
      if (m.sender.isEmpty || m.sender.length > MaxStringLength)
        Left("Invalid sender field")
      else if (m.content.length > MaxStringLength)
        Left("Content too long")
      else if (m.timestamp < 0 || m.timestamp > System.currentTimeMillis() + 60000)
