    case m: CommandMessage =>
      if (!AllowedCommands.contains(m.command))
        Left(s"Disallowed command: ${m.command}")
      else if (m.args.length > MaxArgs)
        Left("Too many arguments")
      else if (m.args.exists(_.length > MaxStringLength))
        Left("Argument too long")
      else if (m.args.exists(containsDangerousContent))
        Left("Dangerous content in arguments")
      else
        Right(m)

    case m: StatusMessage =>
      if (m.code < 0 || m.code > 999)
        Left("Invalid status code")
      else if (m.description.length > MaxStringLength)
        Left("Description too long")
      else
        Right(m)

    case m: HeartbeatMessage =>
      if (m.nodeId.isEmpty || m.nodeId.length > 256)
        Left("Invalid nodeId")
      else if (!m.nodeId.matches("^[a-zA-Z0-9._-]+$"))
        Left("NodeId contains invalid characters")
      else if (m.uptimeSeconds < 0)
        Left("Invalid uptime")
      else
        Right(m)
  }

  private def containsDangerousContent(s: String): Boolean = {
    val lower = s.toLowerCase
    lower.contains("<script") || lower.contains("javascript:") ||
      lower.contains("${") || lower.contains("#{")
  }
