        case "status" => sender() ! StatusMessage(200, "running")
        case "list" => sender() ! StatusMessage(200, "node-list-placeholder")
        case "info" => sender() ! StatusMessage(200, "info-placeholder")
        case "stop" =>
          log.info("Stop command received")
          sender() ! StatusMessage(200, "stopping")
        case _ => sender() ! StatusMessage(400, "unknown command")
      }

    case msg: StatusMessage =>
      log.info(s"Status: ${msg.code} - ${msg.description}")

    case msg: HeartbeatMessage =>
      log.info(s"Heartbeat from node ${msg.nodeId}, uptime: ${msg.uptimeSeconds}s")

