  }
}

// TCP connection handler that safely deserializes incoming data
class ConnectionHandlerActor(processor: akka.actor.ActorRef) extends Actor with ActorLogging {
  import Tcp._

  private var buffer = ByteString.empty
  private val MaxBufferSize = 2 * 1024 * 1024

  override def receive: Receive = {
    case Received(data) =>
      buffer ++= data

      if (buffer.size > MaxBufferSize) {
        log.warning("Buffer overflow from remote connection, closing")
        buffer = ByteString.empty
        sender() ! Close
      } else {
        processBuffer()
      }

    case PeerClosed =>
      log.info("Peer closed connection")
      if (buffer.nonEmpty) {
        processMessage(buffer.toArray)
        buffer = ByteString.empty
      }
      context.stop(self)

    case ErrorClosed(cause) =>
      log.warning(s"Connection error: $cause")
      context.stop(self)

    case Closed =>
      log.info("Connection closed")
      context.stop(self)
  }

  private def processBuffer(): Unit = {
    // Simple length-prefixed framing: first 4 bytes = message length (big-endian)
    while (buffer.size >= 4) {
      val length = ((buffer(0) & 0xFF) << 24) |
        ((buffer(1) & 0xFF) << 16) |
        ((buffer(2) & 0xFF) << 8) |
        (buffer(3) & 0xFF)

      if (length < 0 || length > MaxBufferSize) {
        log.warning(s"Invalid frame length: $length, closing connection")
        buffer = ByteString.empty
        sender() ! Close
        return
      }

      if (buffer.size >= 4 + length) {
        val messageBytes = buffer.slice(4, 4 + length).toArray
        buffer = buffer.drop(4 + length)
        processMessage(messageBytes)
      } else {
        return // Wait for more data
      }
    }
  }

  private def processMessage(data: Array[Byte]): Unit = {
    // SAFE: Using JSON deserialization instead of Java ObjectInputStream
    SafeDeserializer.deserialize(data) match {
      case Right(message) =>
        log.info(s"Successfully deserialized and validated message: ${message.getClass.getSimpleName}")
        processor ! message

      case Left(error) =>
        log.warning(s"Rejected untrusted message: $error")
    }
  }
}

// TCP server actor
class TcpServerActor(host: String, port: Int, processor: akka.actor.ActorRef) extends Actor with ActorLogging {
  import Tcp._
  import context.system

  IO(Tcp) ! Bind(self, new InetSocketAddress(host, port))

  override def receive: Receive = {
    case Bound(localAddress) =>
      log.info(s"Server bound to $localAddress")

    case CommandFailed(_: Bind) =>
      log.error(s"Failed to bind to $host:$port")
      context.stop(self)

    case Connected(remote, _) =>
      log.info(s"New connection from $remote")
      val handler = context.actorOf(Props(new ConnectionHandlerActor(processor)))
      sender() ! Tcp.Register(handler)
  }
}

